import React, { useState } from 'react';
import {
    Container,
    Box,
    Typography,
    Paper,
} from '@mui/material';
import FileUpload from '../components/FileUpload';
import { AnalysisResult, ModelMetrics, AttackStatistics } from '../types';

const Upload: React.FC = () => {
    const [analysisData, setAnalysisData] = useState<{
        result: AnalysisResult;
        metrics: ModelMetrics;
        stats: AttackStatistics;
    } | null>(null);

    const handleAnalysisComplete = (
        result: AnalysisResult,
        metrics: ModelMetrics,
        stats: AttackStatistics
    ) => {
        setAnalysisData({ result, metrics, stats });
    };

    return (
        <Box sx={{ py: 6, minHeight: '100vh' }}>
            <Container maxWidth="md">
                <Box sx={{ mb: 4, color: 'white', textAlign: 'center' }}>
                    <Typography
                        variant="h4"
                        sx={{
                            fontWeight: 'bold',
                            mb: 2,
                            textShadow: '0 2px 4px rgba(0,0,0,0.2)',
                        }}
                    >
                        Upload Network Logs
                    </Typography>
                    <Typography
                        variant="body1"
                        sx={{
                            opacity: 0.95,
                            textShadow: '0 1px 2px rgba(0,0,0,0.2)',
                        }}
                    >
                        Upload a CSV file containing network log data for intrusion detection analysis
                    </Typography>
                </Box>

                <Paper
                    sx={{
                        background: 'rgba(255, 255, 255, 0.98)',
                        backdropFilter: 'blur(10px)',
                        border: '1px solid rgba(255, 255, 255, 0.3)',
                        p: 4,
                        borderRadius: 2,
                    }}
                >
                    <FileUpload onAnalysisComplete={handleAnalysisComplete} />
                </Paper>
            </Container>
        </Box>
    );
};

export default Upload;
